30	// JSONReporter writes one compact JSON object per window to its encoder.
31	type JSONReporter struct {
32		enc *json.Encoder
33	}
34	
35	// Report emits the summary for one window as a single JSON line.
36	func (r *JSONReporter) Report(window Window) error {
37		out := map[string]any{
38			"windowStart": window.Start.Unix(),
39			"count":       window.Count,
40			"errorRate":   window.ErrorRate,
41			"p50Ms":       window.P50,
42			"p95Ms":       window.P95,
43			"maxLatency":  window.MaxLatency,
44		}
45		return r.enc.Encode(out)
46	}
